css:
.loader {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
  width: 60px;
  aspect-ratio: 1;
  animation: l5-0 1s infinite steps(1);
}.loader::before,.loader::after {content: "";
  position: absolute;
  inset:0 50% 50% 0;
  transform-origin: bottom right;
  animation:l5-1 0.5s infinite linear alternate,l5-2 0.5s infinite steps(1) alternate;
}.loader::after {--s:-1,-1;
}@keyframes l5-0 {0% {transform: scale(1, 1) rotate(0deg)}50% {transform: scale(1,-1) rotate(90deg)}}
@keyframes l5-1 {0% {transform: scale(var(--s,1)) perspective(150px) rotateX( 0deg)}100% {transform: scale(var(--s,1)) perspective(150px) rotateX(180deg)}}@keyframes l5-2 {0% {background:var(--loader-color, #16a34a)}50%{background:var(--loader-color, #16a34a)}}
